queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasOnline_Banking_Platforms ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Online_Banking_Platforms } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasOnline_Banking_Platforms ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Online_Banking_Platforms } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?feature_value WHERE {
  ?online_banking_platforms_features a :Online_Banking_Platforms_Features .
  ?features a :Features .
  ?online_banking_platforms_features p:hasFeatures ?features .
  ?online_banking_platforms a :Online_Banking_Platforms .
  ?online_banking_platforms_features p:hasOnline_Banking_Platforms ?online_banking_platforms .
  ?online_banking_platforms p:name ?name .
  ?features p:feature_value ?feature_value .
} }
}
